const localePopularityRank = Object.fromEntries(localePopularityOrder.map((locale, index) => [locale, index])) as Partial<Record<AppLocale, number>>

function displayLanguageName(locale: AppLocale, displayLocale: string) {
  const normalized = locale.replace("_", "-")
  try {
    return new Intl.DisplayNames([displayLocale], { type: "language" }).of(normalized) || normalized
  } catch {
    try {
      return new Intl.DisplayNames([displayLocale], { type: "language" }).of(normalized.split("-")[0]) || normalized
    } catch {
      return normalized
    }
  }
}

export const supportedLocaleOptions: LocaleOption[] = supportedLocales
  .map((value) => {
    const override = localeLabelOverrides[value]
    const label = override?.label || displayLanguageName(value, value)
    const englishLabel = override?.englishLabel || displayLanguageName(value, "en")
    return {
      value,
      label,
      englishLabel,
      region: localeRegionMap[value] || "asia",
      searchText: `${value} ${label} ${englishLabel} ${override?.searchText || ""}`,
    }
  })
  .sort((a, b) => (localePopularityRank[a.value] ?? 9999) - (localePopularityRank[b.value] ?? 9999))

